import { useState, useEffect } from 'react';
import { update } from '../services/api';
import { useSearchParams } from 'react-router-dom';
import axios from 'axios';

export default function Update() {
  const [id, setId] = useState("");
  const [params] = useSearchParams();

  const [form, setForm] = useState({
    documents_submitted: 0,
    police_verification: "Pending"
  });

  // AUTO-FILL DATA WHEN EDIT CLICKED
  useEffect(() => {
    const idParam = params.get("id");

    if (idParam) {
      setId(idParam);

      axios
        .get(`http://localhost:5000/applications/${idParam}`)
        .then(res => {
          setForm({
            documents_submitted: res.data.documents_submitted,
            police_verification: res.data.police_verification
          });
        })
        .catch(() => {
          alert("Application not found");
        });
    }
  }, [params]);

  const handleUpdate = async (e) => {
    e.preventDefault();

    if (!id) {
      alert("Enter Application ID");
      return;
    }

    await update(id, form);
    alert("Application Updated Successfully");
  };

  return (
    <div className="container">
      <h2>Update Application</h2>

      <input
        placeholder="Application ID"
        value={id}
        onChange={(e) => setId(e.target.value)}
      />

      <br />

      <label>Documents Submitted:</label>
      <select
        value={form.documents_submitted}
        onChange={(e) =>
          setForm({ ...form, documents_submitted: e.target.value })
        }
      >
        <option value={0}>No</option>
        <option value={1}>Yes</option>
      </select>

      <br />

      <label>Police Verification:</label>
      <select
        value={form.police_verification}
        onChange={(e) =>
          setForm({ ...form, police_verification: e.target.value })
        }
      >
        <option value="Pending">Pending</option>
        <option value="Approved">Approved</option>
        <option value="Rejected">Rejected</option>
      </select>

      <br /><br />

      <button onClick={handleUpdate}>Update</button>
    </div>
  );
}
